# -----------------------------
#  Define a 2-layer neural network
# -----------------------------
class SimpleMLP(nn.Module):
    def __init__(self):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(2, 4),   # input -> hidden
            nn.ReLU(),         # activation
            nn.Linear(4, 1),    # hidden -> output
        )

    def forward(self, x):
        return self.net(x)

model = SimpleMLP()
